import { useState } from "react";
import "./Billing.css";

export default function Billing() {

  const [charges, setCharges] = useState([
    { id: 1, service: "Consultation Fee", qty: 1, cost: 500 }
  ]);

  const [insurance, setInsurance] = useState(0);

  // ===== ADD ROW =====
  const addCharge = () => {
    setCharges([
      ...charges,
      { id: Date.now(), service: "", qty: 1, cost: 0 }
    ]);
  };

  // ===== UPDATE =====
  const updateCharge = (id, field, value) => {
    setCharges(
      charges.map(item =>
        item.id === id
          ? { ...item, [field]: value }
          : item
      )
    );
  };

  // ===== DELETE =====
  const deleteCharge = (id) => {
    setCharges(charges.filter(item => item.id !== id));
  };

  // ===== CALCULATIONS =====
  const subtotal = charges.reduce(
    (sum, item) => sum + item.qty * item.cost,
    0
  );

  const amountDue = subtotal - insurance;

  return (
    <div className="billing-page">

      {/* ================= PATIENT STRIP ================= */}
      <div className="billing-patient-bar">
        John Doe | Age: 45 | Male | ID: PT123456
      </div>

      {/* ================= SUMMARY ================= */}
      <div className="billing-summary card">
        <div>
          <b>Visit ID:</b> V12345
        </div>
        <div>
          <b>Visit Date:</b> 11-Jan-2026 10:00 AM
        </div>
        <div>
          <b>Visit Type:</b> OPD
        </div>
        <div>
          <b>Doctor:</b> Dr. John Smith
        </div>
      </div>

      {/* ================= CHARGES ================= */}
      <div className="card">
        <h3>Charges</h3>

        <table className="billing-table">
          <thead>
            <tr>
              <th>Service / Item</th>
              <th>Qty</th>
              <th>Unit Cost</th>
              <th>Total</th>
              <th></th>
            </tr>
          </thead>

          <tbody>
            {charges.map((item) => (
              <tr key={item.id}>
                <td>
                  <input
                    value={item.service}
                    onChange={(e) =>
                      updateCharge(item.id, "service", e.target.value)
                    }
                    placeholder="Service name"
                  />
                </td>

                <td>
                  <input
                    type="number"
                    value={item.qty}
                    onChange={(e) =>
                      updateCharge(item.id, "qty", Number(e.target.value))
                    }
                  />
                </td>

                <td>
                  <input
                    type="number"
                    value={item.cost}
                    onChange={(e) =>
                      updateCharge(item.id, "cost", Number(e.target.value))
                    }
                  />
                </td>

                <td>
                  {(item.qty * item.cost).toFixed(2)}
                </td>

                <td>
                  <button
                    className="delete-btn"
                    onClick={() => deleteCharge(item.id)}
                  >
                    ✕
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {/* ================= TOTALS ================= */}
        <div className="billing-total">

          <div>
            <span>Subtotal:</span>
            <b>{subtotal.toFixed(2)}</b>
          </div>

          <div>
            <span>Insurance Coverage:</span>
            <input
              type="number"
              value={insurance}
              onChange={(e) => setInsurance(Number(e.target.value))}
            />
          </div>

          <div className="due">
            <span>Amount Due:</span>
            <b>{amountDue.toFixed(2)}</b>
          </div>
        </div>
      </div>

      {/* ================= ACTIONS ================= */}
      <div className="billing-actions">
        <button onClick={addCharge} className="blue">
          + Add Charge
        </button>

        <button className="gray">
          Print Invoice
        </button>

        <button className="green">
          Process Payment
        </button>

        <button className="red">
          Close Visit
        </button>
      </div>
    </div>
  );
}
